const items = $input.all();

if (!items.length) {
  return [];
}

const candidates = items
  .map(({ json }) => json)
  .filter((file) => file && file.id && file.mimeType !== 'application/vnd.google-apps.folder');

if (!candidates.length) {
  return [];
}

candidates.sort((a, b) => {
  const left = Date.parse(a.createdTime || a.modifiedTime || 0);
  const right = Date.parse(b.createdTime || b.modifiedTime || 0);
  return left - right;
});

const config = $('Config').first().json;
const maxFiles = Math.max(1, Number(config.maxFilesPerRun || 10));

return candidates.slice(0, maxFiles).map((file) => ({
  json: {
    fileId: file.id,
    fileName: file.name ?? null,
    mimeType: file.mimeType ?? null,
    createdTime: file.createdTime ?? null,
    modifiedTime: file.modifiedTime ?? null,
    inboxFolderId: config.inboxFolderId,
    processingLabel: config.processingLabel,
    repoRoot: config.repoRoot,
    expenseSpreadsheetId: config.expenseSpreadsheetId,
    expenseSheetName: config.expenseSheetName,
    idempotencyKey: `drive-${file.id}`,
  },
}));

const item = $input.item;
const bin = item.binary?.data;
if (!bin) throw new Error('Downloaded file did not include binary data.');

const documentBase64 = bin.data;
if (!documentBase64 || typeof documentBase64 !== 'string') {
  throw new Error('Binary payload did not include base64 file content.');
}

const fileName = bin.fileName ?? item.json.fileName ?? null;
const mimeType = bin.mimeType ?? item.json.mimeType ?? null;
const fileId = item.json.fileId ?? null;
const config = $('Config').first().json;
const maxInlineChars = Math.max(20000, Number(config.maxInlineDocumentBase64Chars || 300000));
const payloadTruncated = documentBase64.length > maxInlineChars;
const inlineBase64 = payloadTruncated ? documentBase64.slice(0, maxInlineChars) : documentBase64;

let validatedExamples = [];
try {
  const rows = $('Fetch Validated Examples').all().map(i => i.json || {});
  validatedExamples = rows
    .filter((r) => r.document_type || r.corrected_document_type)
    .slice(0, 20)
    .map((r) => ({
      document_type: r.corrected_document_type || r.document_type || null,
      status: r.corrected_status || r.status || null,
      vendor_or_payee: r.corrected_vendor_or_payee || r.vendor_or_payee || null,
      amount: r.corrected_amount || r.amount || null,
      expense_category: r.corrected_expense_category || r.expense_category || null,
      balance_account: r.corrected_balance_account || r.balance_account || null,
      note: r.correction_reason || r.review_reason || null,
    }));
} catch (e) {
  validatedExamples = [];
}

return {
  json: {
    fileId,
    fileName,
    mimeType,
    fileSize: bin.fileSize ?? null,
    inboxFolderId: item.json.inboxFolderId ?? null,
    processingLabel: item.json.processingLabel,
    repoRoot: item.json.repoRoot,
    expenseSpreadsheetId: item.json.expenseSpreadsheetId,
    expenseSheetName: item.json.expenseSheetName,
    balanceSheetName: item.json.balanceSheetName,
    learningLogSheetName: item.json.learningLogSheetName,
    validationQueueSheetName: item.json.validationQueueSheetName,
    validatedExamplesSheetName: item.json.validatedExamplesSheetName,
    driveFileUrl: fileId ? `https://drive.google.com/file/d/${fileId}/view` : null,
    idempotencyKey: item.json.idempotencyKey ?? (fileId ? `drive-${fileId}` : null),
    payloadTruncated,
    originalDocumentBase64Length: documentBase64.length,
    documentBase64: inlineBase64,
    aiInput: {
      file_name: fileName,
      mime_type: mimeType,
      drive_file_url: fileId ? `https://drive.google.com/file/d/${fileId}/view` : null,
      payload_truncated: payloadTruncated,
      original_document_base64_length: documentBase64.length,
      document_base64: inlineBase64,
      validated_examples: validatedExamples,
    },
  },
  binary: item.binary,
};

const item = $input.item;
const result = item.json.agentOutput ?? {};

return {
  json: {
    sourceFileId: item.json.sourceFileId,
    sourceFileName: item.json.sourceFileName,
    sourceFileUrl: item.json.sourceFileUrl,
    documentType: item.json.documentType ?? result.document_type ?? 'unknown',
    status: item.json.status ?? result.status ?? 'processed',
    reviewQueueRequired: Boolean(item.json.reviewQueueRequired),
    confidence: item.json.confidence ?? result.confidence ?? null,
    postToExpenses: Boolean(item.json.postToExpenses),
    statementEndingBalance: item.json.statementEndingBalance ?? null,
    balanceAccount: item.json.balanceAccount ?? null,
    expenseCategory: item.json.expenseCategory ?? null,
    agentResult: result,
  },
};

const item = $input.item;
const output = item.json.agentOutput ?? {};
const docType = output.document_type ?? item.json.documentType ?? 'unknown';
const shouldPost = item.json.status === 'processed' && !item.json.reviewQueueRequired && (docType === 'invoice' || Boolean(item.json.postToExpenses) || Boolean(output.post_to_expenses));
if (!shouldPost) return [];

const amount = typeof output.amount === 'number' ? output.amount : (output.amount ? Number(output.amount) : null);
if (amount == null || Number.isNaN(amount)) return [];

return [{
  json: {
    jobId: `expense-${item.json.sourceFileId || 'unknown'}`,
    sourceFileId: item.json.sourceFileId,
    sourceFileName: item.json.sourceFileName,
    sourceFileUrl: item.json.sourceFileUrl,
    vendorOrPayee: output.vendor_or_payee ?? null,
    invoiceNumber: output.invoice_number ?? null,
    documentDate: output.document_date ?? null,
    dueDate: null,
    amount,
    currency: output.currency ?? 'USD',
    suggestedCategory: output.expense_category ?? item.json.expenseCategory ?? null,
    suggestedEntity: null,
    confidence: output.confidence ?? null,
    summary: output.summary ?? null,
    status: item.json.status ?? output.status ?? null,
    extractedAt: new Date().toISOString()
  }
}];

const item = $input.item;
const cfg = $('Config').first().json;
const docType = item.json.documentType || 'unknown';
const status = item.json.status || 'processed';
const needsReview = Boolean(item.json.reviewQueueRequired);

let targetFolderId = cfg.doneOtherFolderId;
let route = 'done_other';

if (status === 'failed') {
  targetFolderId = cfg.errorFolderId;
  route = 'error';
} else if (needsReview || status === 'needs_review') {
  targetFolderId = cfg.reviewFolderId;
  route = 'review';
} else if (docType === 'invoice') {
  targetFolderId = cfg.doneInvoicesFolderId;
  route = 'done_invoices';
} else if (docType === 'bank_statement') {
  targetFolderId = cfg.doneBankStatementsFolderId || cfg.doneOtherFolderId;
  route = 'done_bank_statements';
}

if (!targetFolderId || String(targetFolderId).startsWith('REPLACE_WITH_')) {
  throw new Error(`Missing target folder ID for route: ${route}`);
}

return [{ json: { ...item.json, targetFolderId, route } }];

const item = $input.item;
const source = $('Prepare Processing Context').item.json;
const config = $('Config').first().json;

let raw = item.json.output ?? item.json.response ?? item.json.text ?? item.json.result ?? '';
if (typeof raw !== 'string') raw = JSON.stringify(raw ?? {});
raw = raw.trim();
if (raw.startsWith('```')) {
  const lines = raw.split('\n');
  if (lines[0].startsWith('```')) lines.shift();
  if (lines.length && lines[lines.length - 1].startsWith('```')) lines.pop();
  raw = lines.join('\n').trim();
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    document_type: 'unknown',
    status: 'failed',
    confidence: 0,
    vendor_or_payee: null,
    document_date: null,
    amount: null,
    currency: null,
    invoice_number: null,
    review_reason: `Invalid AI JSON: ${e.message}`,
    summary: 'AI output parse failed',
    post_to_expenses: false,
    expense_category: null,
    statement_ending_balance: null,
    balance_account: null,
  };
}

const allowedTypes = new Set(['invoice', 'bank_statement', 'other', 'unknown']);
const allowedStatus = new Set(['processed', 'needs_review', 'failed']);
const type = allowedTypes.has(parsed.document_type) ? parsed.document_type : 'unknown';
const threshold = Number(config.confidenceReviewThreshold ?? 0.75);
let confidence = Number(parsed.confidence ?? 0);
if (!Number.isFinite(confidence)) confidence = 0;
confidence = Math.max(0, Math.min(1, confidence));
let status = allowedStatus.has(parsed.status) ? parsed.status : 'processed';

const amount = typeof parsed.amount === 'number' ? parsed.amount : (parsed.amount ? Number(parsed.amount) : null);
const endingBalance = typeof parsed.statement_ending_balance === 'number'
  ? parsed.statement_ending_balance
  : (parsed.statement_ending_balance ? Number(parsed.statement_ending_balance) : null);

let reviewReason = parsed.review_reason ?? null;
if (status === 'processed' && confidence < threshold) {
  status = 'needs_review';
  reviewReason = reviewReason || `Confidence ${confidence.toFixed(2)} below threshold ${threshold}`;
}

if (source.payloadTruncated && status !== 'failed') {
  status = 'needs_review';
  reviewReason = reviewReason || 'Input payload was truncated before AI classification';
}

const reviewQueueRequired = status !== 'processed' || Boolean(reviewReason);

return [{
  json: {
    agentOutput: {
      ...parsed,
      review_reason: reviewReason,
    },
    documentType: type,
    status,
    reviewQueueRequired,
    confidence,
    vendorOrPayee: parsed.vendor_or_payee ?? null,
    invoiceNumber: parsed.invoice_number ?? null,
    documentDate: parsed.document_date ?? null,
    amount: amount == null || Number.isNaN(amount) ? null : amount,
    currency: parsed.currency ?? 'USD',
    summary: parsed.summary ?? null,
    postToExpenses: Boolean(parsed.post_to_expenses),
    expenseCategory: parsed.expense_category ?? null,
    statementEndingBalance: endingBalance == null || Number.isNaN(endingBalance) ? null : endingBalance,
    balanceAccount: parsed.balance_account ?? null,
    sourceFileId: source.fileId,
    sourceFileName: source.fileName,
    sourceFileUrl: source.driveFileUrl,
    idempotencyKey: source.idempotencyKey ?? (source.fileId ? `drive-${source.fileId}` : null),
    payloadTruncated: Boolean(source.payloadTruncated),
    reviewReason,
  }
}];

const item = $input.item;
const output = item.json.agentOutput ?? {};
const docType = output.document_type ?? item.json.documentType ?? 'unknown';
if (docType !== 'bank_statement' || item.json.status !== 'processed' || item.json.reviewQueueRequired) return [];

return [{
  json: {
    sourceFileId: item.json.sourceFileId,
    sourceFileName: item.json.sourceFileName,
    sourceFileUrl: item.json.sourceFileUrl,
    statementDate: output.document_date ?? item.json.documentDate ?? null,
    endingBalance: output.statement_ending_balance ?? item.json.statementEndingBalance ?? null,
    balanceAccount: output.balance_account ?? item.json.balanceAccount ?? null,
    confidence: output.confidence ?? item.json.confidence ?? null,
    summary: output.summary ?? item.json.summary ?? null,
    status: item.json.status ?? output.status ?? null,
    loggedAt: new Date().toISOString()
  }
}];

const item = $input.item;
if (!item.json.reviewQueueRequired) return [];
const output = item.json.agentOutput ?? {};
return [{
  json: {
    queuedAt: new Date().toISOString(),
    sourceFileId: item.json.sourceFileId,
    sourceFileName: item.json.sourceFileName,
    sourceFileUrl: item.json.sourceFileUrl,
    suggested_document_type: item.json.documentType ?? output.document_type ?? null,
    suggested_status: item.json.status ?? output.status ?? null,
    suggested_vendor_or_payee: output.vendor_or_payee ?? null,
    suggested_amount: output.amount ?? null,
    suggested_expense_category: output.expense_category ?? null,
    suggested_balance_account: output.balance_account ?? null,
    confidence: item.json.confidence ?? output.confidence ?? null,
    review_reason: item.json.reviewReason ?? output.review_reason ?? null,
    summary: output.summary ?? null,
    validation_status: "pending",
    reviewer: null,
    reviewedAt: null,
    correction_reason: null
  }
}];

const cfg = $input.item.json;

const requiredKeys = [
  'inboxFolderId',
  'doneInvoicesFolderId',
  'doneBankStatementsFolderId',
  'doneOtherFolderId',
  'reviewFolderId',
  'errorFolderId',
  'expenseSpreadsheetId',
  'expenseSheetName',
  'balanceSheetName',
  'learningLogSheetName',
  'validationQueueSheetName',
  'validatedExamplesSheetName',
];

const missing = requiredKeys.filter((key) => {
  const value = cfg[key];
  return value == null || String(value).trim() === '' || String(value).startsWith('REPLACE_WITH_');
});

if (missing.length) {
  throw new Error(`Config placeholders or missing values: ${missing.join(', ')}`);
}

const maxFilesPerRun = Number(cfg.maxFilesPerRun ?? 10);
if (!Number.isFinite(maxFilesPerRun) || maxFilesPerRun < 1 || maxFilesPerRun > 100) {
  throw new Error('maxFilesPerRun must be between 1 and 100');
}

const confidenceThreshold = Number(cfg.confidenceReviewThreshold ?? 0.75);
if (!Number.isFinite(confidenceThreshold) || confidenceThreshold <= 0 || confidenceThreshold >= 1) {
  throw new Error('confidenceReviewThreshold must be between 0 and 1');
}

return [{ json: cfg }];
